const email = $input.first().json;

const from = email.from?.text || email.from?.value?.[0]?.address || email.from || 'Unknown';
const subject = email.subject || '(без темы)';
const body = (email.text || email.html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 2000);
const date = email.date || new Date().toISOString();
const emailId = 'em_' + Date.now();

// Detect priority
const haystack = (subject + ' ' + body).toLowerCase();
const urgentWords = ['оплата', 'оплачен', 'чек', 'код', 'подтвержд', 'invoice', 'payment', 'receipt', 'verify', 'verification', 'код подтверждения', 'пароль', 'password', 'активац', 'заказ', 'order'];
const isUrgent = urgentWords.some(w => haystack.includes(w));

return [{ json: { emailId, from, subject, body, date, isUrgent } }];

const parsed = $('Parse Email').first().json;
const gptRes = $input.first().json;
const summary = gptRes.choices?.[0]?.message?.content || 'Не удалось обработать письмо';

const msg = '📧 Новое письмо:\nОт: ' + parsed.from + '\n\n' + summary + '\n\n💬 Спроси подробнее — я помню контекст';

return [{ json: { emailId: parsed.emailId, from: parsed.from, subject: parsed.subject, body: parsed.body, date: parsed.date, summary, message: msg } }];
